            install_url = "https://addons.mozilla.org/firefox/downloads/latest/1password-x-password-manager/latest.xpi";
            installation_mode = "force_installed";
          };
          # Vimium
          "{d7742d87-e61d-4b78-b8a1-b469842139fa}" = {
            install_url = "https://addons.mozilla.org/firefox/downloads/latest/vimium-ff/latest.xpi";
            installation_mode = "force_installed";
          };
          # SponsorBlock
          "sponsorBlocker@ajay.app" = {
            install_url = "https://addons.mozilla.org/firefox/downloads/latest/sponsorblock/latest.xpi";
            installation_mode = "force_installed";
          };
          # Facebook Container
          "@contain-facebook" = {
            install_url = "https://addons.mozilla.org/firefox/downloads/latest/facebook-container/latest.xpi";
            installation_mode = "force_installed";
          };
          # Enhancer for YouTube
          "enhancerforyoutube@maximerf.addons.mozilla.org" = {
            install_url = "https://addons.mozilla.org/firefox/downloads/latest/enhancer-for-youtube/latest.xpi";
            installation_mode = "force_installed";
          };
        };
      };
    };

    gnupg.agent = {
      enable = true;
      pinentryPackage = pkgs.pinentry-curses;
    };

    obs-studio = {
      enable = true;
      plugins = with pkgs.obs-studio-plugins; [
        wlrobs
        obs-backgroundremoval
        obs-pipewire-audio-capture
        obs-gstreamer
        obs-vkcapture
      ];
    };
    #regreet = {
    #  enable = true;
    #  settings = {
    #    background = {
    #      path =
    #        "${wallpaperPkg}/nix-wallpaper-nineish-catppuccin-macchiato.png";
    #      fit = "Cover";
    #    };
    #    GTK = { application_prefer_dark_theme = true; };
    #    appearance = { greeting_msg = "Mr. Anderson, Welcome back!"; };
    #  };
    #};
    steam.enable = true;
    sway.enable = true;
    virt-manager.enable = true;
    zsh.enable = true;
  };

  # recommended so PipeWire gets realtime priority
  security.rtkit.enable = true;

  services = {
    blueman.enable = true;
    gnome.gnome-keyring.enable = true;
    libinput.enable = true;
    mpd = {
      enable = true;
      user = "${cfg.username}";
      group = "users";
      settings = {
        music_directory = "/home/${cfg.username}/Music";
        audio_output = [
          {
            type = "pipewire";
            name = "PipeWire Sound Server";
          }
        ];
      };
    };
    openssh.enable = true;
    pipewire = {
      enable = true;
      alsa.enable = true;
      alsa.support32Bit = true;
      pulse.enable = true;
      wireplumber.enable = true;
    };
    greetd = {
      enable = true;
      settings = {
        default_session = {
          command = "${pkgs.tuigreet}/bin/tuigreet --time --cmd 'sway --unsupported-gpu'";
          user = "${cfg.username}";
        };
      };
    };
    keyd = {
      enable = true;
      keyboards.default = {
        ids = [ "*" ];
        settings.main.capslock = "overload(control, esc)";
      };
    };

    upower.enable = true;

    transmission = {
      enable = true;
      package = pkgs.transmission_4;
      user = "${cfg.username}";
      group = "users";
      webHome = pkgs.flood-for-transmission;
      openRPCPort = true;
      settings = {
        rpc-bind-address = "0.0.0.0";
        rpc-whitelist-enabled = false;
        download-dir = "/home/${cfg.username}/Downloads";
        incomplete-dir = "/home/${cfg.username}/Downloads/.incomplete";
        incomplete-dir-enabled = true;
      };
    };

    luna-podcatcher = {
      enable = true;
      port = 19091;
      installCli = true;

      environment = {
        LUNA_LOG_LEVEL = "info";
        LUNA_TRANSCRIBE_ENDPOINT = "http://127.0.0.1:8910/inference";
        LUNA_TRANSCRIBE_LANGUAGE = "en";
      };

      jobs = {
        crawl = {
          enable = true;
          onCalendar = "*:0/30"; # every 30 minutes instead of hourly
        };
        download.enable = true;
        transcribe.enable = true;
        gc.enable = true;
      };

      database = {
        createLocally = true;
        user = "luna-podcatcher";
        name = "luna-podcatcher";

        container = {
          enable = true;
          image = "postgres:16-alpine"; # docker container image
          port = 54329; # host-local TCP port (bound to 127.0.0.1)
          dataDir = "/var/lib/luna-podcatcher/pgdata";
        };
      };

    };

  };

  systemd = {
    # Create transmission download directories
    tmpfiles.rules = [
      "d /home/${cfg.username}/Downloads 0755 ${cfg.username} users -"
      "d /home/${cfg.username}/Downloads/.incomplete 0755 ${cfg.username} users -"
    ];

    # Set XDG_RUNTIME_DIR for MPD to connect to PipeWire
    services.mpd.environment = {
      XDG_RUNTIME_DIR = "/run/user/1000";
    };

    # Enable lingering for the ${cfg.username} user so the service starts at boot
    # even when the user is not logged in
    user.services."user@${cfg.username}".enable = true;
  };

  xdg.portal.enable = true;

  system.stateVersion = "25.05";

}

